"use client";

import React from "react";
import { Controller, FieldPath, FieldValues, useWatch } from "react-hook-form";

import {
  Field,
  FieldContent,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field";
import { cn } from "@/lib/utils";

import { FormFieldType } from "./constants";
import { FieldSkeleton } from "./FieldSkeleton";
import { FieldControlRenderer, HEIGHT_CLASSES } from "./render-field-control";
import { FieldRendererProps } from "./types";

function FieldRendererInner<
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>,
  TRow extends Record<string, unknown> = Record<string, unknown>
>(props: FieldRendererProps<TFieldValues, TName, TRow>) {
  const {
    control,
    name,
    label,
    description,
    required,
    disabled,
    wrapperClassName,
    hideLabel,
    hideDescription,
    hideMessage,
    labelClassName,
    descriptionClassName,
    messageClassName,
    fieldType,
    height,
    renderSkeleton,
  } = props;
  const values = useWatch({ control }) as TFieldValues;

  const rendersInlineLabel =
    fieldType === FormFieldType.CHECKBOX || fieldType === FormFieldType.SWITCH;

  if (props.show && !props.show(values)) {
    return null;
  }

  if (fieldType === FormFieldType.SKELETON) {
    return renderSkeleton ? (
      renderSkeleton({} as never)
    ) : (
      <FieldSkeleton className={HEIGHT_CLASSES[height ?? "md"]} />
    );
  }

  return (
    <Controller
      control={control}
      name={name}
      disabled={disabled}
      render={({ field, fieldState }) => {
        const baseId = String(name).replace(/\./g, "-");
        const fieldId = `${baseId}-field`;
        const descriptionId = `${fieldId}-description`;
        const messageId = `${fieldId}-message`;
        const invalid = fieldState.invalid;

        return (
          <Field
            data-invalid={invalid}
            data-disabled={disabled || undefined}
            className={cn("w-full", wrapperClassName)}
            orientation={rendersInlineLabel ? "horizontal" : "vertical"}
          >
            {rendersInlineLabel ? (
              <>
                <FieldControlRenderer
                  field={field}
                  fieldId={fieldId}
                  descriptionId={descriptionId}
                  messageId={messageId}
                  invalid={invalid}
                  props={props}
                />
                <FieldContent>
                  {!hideLabel && label && (
                    <FieldLabel
                      htmlFor={fieldId}
                      className={cn(
                        "text-sm font-medium leading-none",
                        labelClassName
                      )}
                    >
                      {label}
                      {required && <span className="text-destructive">*</span>}
                    </FieldLabel>
                  )}

                  {!hideDescription && description && (
                    <FieldDescription
                      id={descriptionId}
                      className={cn(
                        "text-xs leading-relaxed text-muted-foreground",
                        descriptionClassName
                      )}
                    >
                      {description}
                    </FieldDescription>
                  )}

                  {!hideMessage && invalid && (
                    <FieldError
                      id={messageId}
                      errors={[fieldState.error]}
                      className={cn("text-xs font-medium", messageClassName)}
                    />
                  )}
                </FieldContent>
              </>
            ) : (
              <FieldContent>
                {!hideLabel && label && (
                  <FieldLabel
                    htmlFor={fieldId}
                    className={cn(
                      "text-sm font-medium leading-none",
                      labelClassName
                    )}
                  >
                    {label}
                    {required && <span className="text-destructive">*</span>}
                  </FieldLabel>
                )}

                <FieldControlRenderer
                  field={field}
                  fieldId={fieldId}
                  descriptionId={descriptionId}
                  messageId={messageId}
                  invalid={invalid}
                  props={props}
                />

                {!hideDescription && description && (
                  <FieldDescription
                    id={descriptionId}
                    className={cn(
                      "text-xs leading-relaxed text-muted-foreground",
                      descriptionClassName
                    )}
                  >
                    {description}
                  </FieldDescription>
                )}

                {!hideMessage && invalid && (
                  <FieldError
                    id={messageId}
                    errors={[fieldState.error]}
                    className={cn("text-xs font-medium", messageClassName)}
                  />
                )}
              </FieldContent>
            )}
          </Field>
        );
      }}
    />
  );
}

export const FieldRenderer = React.memo(
  FieldRendererInner
) as typeof FieldRendererInner;

/** @deprecated Use FieldRenderer instead. */
export const DynamicFormField = FieldRenderer;

"use client";

import React from "react";
import { FieldPath, FieldValues } from "react-hook-form";

import { Checkbox } from "@/components/ui/checkbox";
import {
  InputGroup,
  InputGroupInput,
  InputGroupText,
  InputGroupTextarea,
} from "@/components/ui/input-group";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { cn } from "@/lib/utils";

import { FormFieldType } from "./constants";
import { FieldSkeleton } from "./FieldSkeleton";
import { applyMask } from "../fields/utils/mask";
import { AsyncSelectField } from "../fields/controls/AsyncSelectField";
import { CurrencyField } from "../fields/controls/CurrencyField";
import { DateField } from "../fields/controls/DateField";
import { MultiSelectField } from "../fields/controls/MultiSelectField";
import { NumberField } from "../fields/controls/NumberField";
import { OtpField } from "../fields/controls/OtpField";
import { PasswordField } from "../fields/controls/PasswordField";
import { PercentField } from "../fields/controls/PercentField";
import { PhoneField } from "../fields/controls/PhoneField";
import { ComboboxField } from "../fields/controls/ComboboxField";
import { RadioGroupField } from "../fields/controls/RadioGroupField";
import { SelectField } from "../fields/controls/SelectField";
import { SliderField } from "../fields/controls/SliderField";
import {
  FieldControlProps,
  InputHeight,
  SelectLabelKey,
  StringKeyOf,
} from "./types";

export const HEIGHT_CLASSES: Record<InputHeight, string> = {
  sm: "h-8",
  md: "h-9",
  lg: "h-10",
  xl: "h-11",
  auto: "h-auto",
};

const DEFAULT_HEIGHTS: Partial<Record<FormFieldType, InputHeight>> = {
  [FormFieldType.INPUT]: "md",
  [FormFieldType.PASSWORD]: "md",
  [FormFieldType.TEXTAREA]: "auto",
  [FormFieldType.NUMBER]: "md",
  [FormFieldType.DATE_PICKER]: "md",
  [FormFieldType.SELECT]: "md",
  [FormFieldType.SINGLE_SELECT]: "md",
  [FormFieldType.MULTI_SELECT]: "md",
  [FormFieldType.COMMAND]: "md",
  [FormFieldType.RADIO_GROUP]: "auto",
  [FormFieldType.SLIDER]: "auto",
  [FormFieldType.OTP]: "auto",
  [FormFieldType.PHONE_INPUT]: "md",
  [FormFieldType.CHECKBOX]: "auto",
  [FormFieldType.HIDDEN]: "auto",
  [FormFieldType.SKELETON]: "auto",
  [FormFieldType.CURRENCY]: "md",
  [FormFieldType.PERCENT]: "md",
  [FormFieldType.MASKED]: "md",
  [FormFieldType.ASYNC_SELECT]: "md",
  [FormFieldType.SWITCH]: "auto",
  [FormFieldType.FILE_UPLOAD]: "auto",
};

export const FieldControlRenderer = <
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>,
  TRow extends Record<string, unknown> = Record<string, unknown>
>({
  field,
  fieldId,
  descriptionId,
  messageId,
  invalid,
  props,
}: FieldControlProps<TFieldValues, TName, TRow>) => {
  const {
    fieldType,
    prefix,
    suffix,
    className,
    disabled,
    height,
    inputClassName,
  } = props;
  const hasOverlayContent =
    fieldType === FormFieldType.SELECT ||
    fieldType === FormFieldType.SINGLE_SELECT ||
    fieldType === FormFieldType.MULTI_SELECT ||
    fieldType === FormFieldType.COMMAND ||
    fieldType === FormFieldType.ASYNC_SELECT ||
    fieldType === FormFieldType.PHONE_INPUT;
  const overlayLayerClass =
    fieldType === FormFieldType.ASYNC_SELECT
      ? "z-30"
      : hasOverlayContent
        ? "z-10"
        : undefined;

  const heightClass =
    HEIGHT_CLASSES[height || DEFAULT_HEIGHTS[fieldType] || "md"];
  const describedBy = invalid
    ? [descriptionId, messageId].filter(Boolean).join(" ")
    : descriptionId;
  const hasAffixes = Boolean(prefix || suffix);
  const groupClass = cn(
    "flex w-full items-center rounded-md border border-border bg-background/95 transition-colors",
    "focus-within:border-primary/70 focus-within:ring-1 focus-within:ring-primary/25",
    "hover:border-muted-foreground/40 data-[invalid=true]:border-destructive/60",
    hasOverlayContent && "overflow-visible",
    overlayLayerClass,
    disabled && "cursor-not-allowed opacity-60",
    heightClass,
    className
  );
  const inputClasses = cn(
    "w-full bg-transparent text-sm leading-none",
    "placeholder:text-muted-foreground/60",
    "border-0 outline-none",
    "focus-visible:ring-0 focus-visible:ring-offset-0",
    inputClassName
  );

  if (fieldType === FormFieldType.CHECKBOX) {
    return (
      <Checkbox
        id={fieldId}
        checked={!!field.value}
        onCheckedChange={(checked) => field.onChange(checked)}
        disabled={disabled}
        aria-invalid={invalid}
        aria-describedby={describedBy || undefined}
        aria-label={props.hideLabel ? props.label : undefined}
      />
    );
  }

  if (fieldType === FormFieldType.HIDDEN) {
    return <input type="hidden" {...field} value={field.value ?? ""} />;
  }

  if (fieldType === FormFieldType.RADIO_GROUP) {
    return (
      <RadioGroupField
        field={field}
        fieldId={fieldId}
        descriptionId={descriptionId}
        messageId={messageId}
        invalid={invalid}
        props={props}
      />
    );
  }

  if (fieldType === FormFieldType.SLIDER) {
    return (
      <SliderField
        field={field}
        fieldId={fieldId}
        descriptionId={descriptionId}
        messageId={messageId}
        invalid={invalid}
        props={props}
      />
    );
  }

  if (fieldType === FormFieldType.OTP) {
    return (
      <OtpField
        field={field}
        fieldId={fieldId}
        descriptionId={descriptionId}
        messageId={messageId}
        invalid={invalid}
        props={props}
      />
    );
  }

  if (fieldType === FormFieldType.SKELETON) {
    return props.renderSkeleton ? (
      props.renderSkeleton(field)
    ) : (
      <FieldSkeleton className={HEIGHT_CLASSES[props.height ?? "md"]} />
    );
  }

  if (fieldType === FormFieldType.SWITCH) {
    return (
      <Switch
        {...props.switchProps}
        id={fieldId}
        checked={!!field.value}
        onCheckedChange={(checked) => field.onChange(checked)}
        disabled={disabled}
        aria-invalid={invalid}
        aria-describedby={describedBy || undefined}
        aria-label={props.hideLabel ? props.label : undefined}
      />
    );
  }

  if (fieldType === FormFieldType.FILE_UPLOAD) {
    return (
      <Input
        {...props.inputProps}
        id={fieldId}
        name={field.name}
        type="file"
        disabled={disabled ?? props.inputProps?.disabled}
        aria-invalid={invalid}
        aria-describedby={describedBy || undefined}
        className={cn("cursor-pointer", props.inputProps?.className)}
        onBlur={field.onBlur}
        onChange={(event) => {
          const files = event.target.files;
          field.onChange(props.inputProps?.multiple ? files : files?.[0] ?? null);
        }}
      />
    );
  }

  let controlChild: React.ReactNode = null;

  switch (fieldType) {
    case FormFieldType.TEXTAREA:
      controlChild = (
        <InputGroupTextarea
          {...props.textareaProps}
          {...field}
          id={fieldId}
          disabled={disabled ?? props.textareaProps?.disabled}
          placeholder={props.placeholder ?? props.textareaProps?.placeholder ?? ""}
          aria-invalid={invalid}
          aria-describedby={describedBy || undefined}
          className={cn(
            "resize-none py-1",
            inputClasses,
            props.textareaProps?.className
          )}
        />
      );
      break;

    case FormFieldType.PASSWORD:
      controlChild = (
        <PasswordField
          {...props.passwordProps}
          {...field}
          id={fieldId}
          disabled={disabled ?? props.passwordProps?.disabled}
          placeholder={props.passwordProps?.placeholder ?? props.placeholder ?? ""}
          aria-invalid={invalid}
          aria-describedby={describedBy || undefined}
          className={cn(inputClasses, props.passwordProps?.className)}
        />
      );
      break;

    case FormFieldType.DATE_PICKER:
      controlChild = (
        <DateField
          value={field.value}
          onChange={field.onChange}
          placeholder={props.placeholder}
          disabled={disabled}
          className="w-full"
          inputClassName={inputClasses}
          inputId={fieldId}
          ariaInvalid={invalid}
          ariaDescribedBy={describedBy || undefined}
        />
      );
      break;

    case FormFieldType.PHONE_INPUT:
      controlChild = (
        <PhoneField
          {...field}
          id={fieldId}
          placeholder={props.placeholder}
          disabled={disabled}
          aria-invalid={invalid}
          aria-describedby={describedBy || undefined}
          className={cn(inputClasses, "h-full w-full border-none text-right")}
        />
      );
      break;

    case FormFieldType.SELECT:
      controlChild = (
        <SelectField
          field={field}
          data={props.data ?? []}
          label={props.label ?? ""}
          placeholder={props.placeholder}
          disabled={disabled}
          labelKey={props.labelKey ?? "label"}
          valueKey={props.valueKey ?? "value"}
          inputId={fieldId}
          ariaInvalid={invalid}
          ariaDescribedBy={describedBy || undefined}
          className={cn(
            inputClasses,
            hasAffixes &&
              "h-full rounded-none border-0 bg-transparent px-3 shadow-none hover:bg-transparent focus-visible:ring-0"
          )}
        />
      );
      break;

    case FormFieldType.SINGLE_SELECT:
    case FormFieldType.MULTI_SELECT:
      controlChild = (
        fieldType === FormFieldType.SINGLE_SELECT ? (
          <ComboboxField
            field={field}
            data={props.data ?? []}
            label={props.label ?? ""}
            placeholder={props.placeholder}
            disabled={disabled}
            labelKey={props.labelKey ?? "label"}
            valueKey={props.valueKey ?? "value"}
            inputId={fieldId}
            ariaInvalid={invalid}
            ariaDescribedBy={describedBy || undefined}
            className={cn(
              inputClasses,
              hasAffixes &&
                "h-full rounded-none border-0 bg-transparent px-3 shadow-none hover:bg-transparent focus-visible:ring-0"
            )}
          />
        ) : (
        <MultiSelectField
          field={field}
          fieldId={fieldId}
          descriptionId={descriptionId}
          messageId={messageId}
          invalid={invalid}
          props={props}
        />
        )
      );
      break;

    case FormFieldType.COMMAND:
      controlChild = (
        <ComboboxField
          field={field}
          data={props.data ?? []}
          label={props.label ?? ""}
          placeholder={props.placeholder}
          disabled={disabled}
          labelKey={props.labelKey ?? "label"}
          valueKey={props.valueKey ?? "value"}
          inputId={fieldId}
          ariaInvalid={invalid}
          ariaDescribedBy={describedBy || undefined}
          className={cn(
            inputClasses,
            hasAffixes &&
              "h-full rounded-none border-0 bg-transparent px-3 shadow-none hover:bg-transparent focus-visible:ring-0"
          )}
        />
      );
      break;

    case FormFieldType.NUMBER:
      controlChild = (
        <NumberField
          field={field}
          fieldId={fieldId}
          descriptionId={descriptionId}
          messageId={messageId}
          invalid={invalid}
          props={props}
        />
      );
      break;

    case FormFieldType.ASYNC_SELECT: {
      type Row = Record<string, unknown>;
      const asyncData = props.data as Row[] | undefined;
      const valueKey: StringKeyOf<Row> =
        (props.valueKey as StringKeyOf<Row>) ?? ("value" as StringKeyOf<Row>);
      const labelKey: SelectLabelKey<Row> =
        (props.selectLabelKey as SelectLabelKey<Row>) ?? "label";

      controlChild = (
        <AsyncSelectField
          value={field.value}
          onChange={field.onChange}
          data={asyncData}
          loadOptions={props.loadOptions}
          placeholder={props.placeholder}
          disabled={disabled}
          height={height || DEFAULT_HEIGHTS[fieldType] || "md"}
          valueKey={valueKey}
          selectLabelKey={labelKey}
          debounceTime={props.debounceTime ?? 300}
          onAddNew={props.onAddNew}
          addNewLabel={props.addNewLabel}
          iconSearch={props.iconSearch ?? false}
        />
      );
      break;
    }

    case FormFieldType.CURRENCY:
      controlChild = (
        <CurrencyField
          field={field as never}
          props={props as never}
          disabled={disabled}
          className={cn(
            inputClasses,
            "text-right tabular-nums",
            props.className
          )}
        />
      );
      break;

    case FormFieldType.PERCENT:
      controlChild = (
        <PercentField
          field={field}
          props={props}
          disabled={disabled}
          className={cn(inputClasses, props.className)}
        />
      );
      break;

    case FormFieldType.MASKED:
      controlChild = (
        <InputGroupInput
          {...props.inputProps}
          {...field}
          id={fieldId}
          disabled={disabled ?? props.inputProps?.disabled}
          placeholder={
            props.maskPlaceholder ??
            props.placeholder ??
            props.inputProps?.placeholder ??
            ""
          }
          aria-invalid={invalid}
          aria-describedby={describedBy || undefined}
          className={cn(inputClasses, props.inputProps?.className)}
          value={applyMask(field.value ?? "", props.mask ?? "")}
          onChange={(event) => {
            const next = applyMask(event.target.value, props.mask ?? "");
            if (next !== field.value) {
              field.onChange(next);
            }
          }}
        />
      );
      break;

    default:
      controlChild = (
        <InputGroupInput
          {...props.inputProps}
          {...field}
          id={fieldId}
          type={props.inputProps?.type ?? props.type ?? "text"}
          disabled={disabled ?? props.inputProps?.disabled}
          placeholder={props.placeholder ?? props.inputProps?.placeholder ?? ""}
          aria-invalid={invalid}
          aria-describedby={describedBy || undefined}
          className={cn(inputClasses, props.inputProps?.className)}
          onChange={(event) => {
            if ((props.type ?? props.inputProps?.type) === "number") {
              field.onChange(
                event.target.value === "" ? "" : Number(event.target.value)
              );
              return;
            }

            field.onChange(event);
          }}
        />
      );
  }

  return (
    <InputGroup data-invalid={invalid || undefined} className={groupClass}>
      {prefix && (
        <InputGroupText className="min-w-11 justify-center bg-muted/25 px-3 text-muted-foreground">
          {prefix}
        </InputGroupText>
      )}

      <div className="h-full flex-1">{controlChild}</div>

      {suffix && (
        <InputGroupText className="min-w-11 justify-center bg-muted/15 px-3 text-muted-foreground">
          {suffix}
        </InputGroupText>
      )}
    </InputGroup>
  );
};

/** @deprecated Use FieldControlRenderer instead. */
export const DynamicRenderInput = FieldControlRenderer;

"use client";

import { cn } from "@/lib/utils";
import { Skeleton } from "@/components/ui/skeleton";

/**
 * Base shimmer skeleton for form fields.
 * Height must be supplied externally via className="h-10"
 */
export function FieldSkeleton({
  rounded = "rounded-md",
  className,
}: {
  rounded?: string;
  className?: string;
}) {
  return (
    <div
      className={cn(
        "relative w-full overflow-hidden",
        rounded,
        className
      )}
    >
      <Skeleton className="w-full h-full" />

      <div
        className={cn(
          "absolute inset-0 -translate-x-full",
          "animate-[shimmer_1.6s_infinite]",
          "bg-linear-to-r from-transparent via-foreground/15 to-transparent"
        )}
      />
    </div>
  );
}

/** @deprecated Use FieldSkeleton instead. */
export const FieldSkeletonLoader = FieldSkeleton;

import type {
  ControllerRenderProps,
  Control,
  FieldPath,
  FieldValues,
} from "react-hook-form";
import type { ComponentProps, ReactNode } from "react";

import { Switch } from "@/components/ui/switch";
import type { FormFieldType } from "./constants";

export type InputHeight = "sm" | "md" | "lg" | "xl" | "auto";
export type FieldColSpan = 1 | 2 | 3 | 4 | "full";

export type StringKeyOf<T> = Extract<keyof T, string>;

export type SelectFormatFn<Value = unknown, Row = unknown> = (
  value: Value,
  row: Row
) => string;

export type SelectLabelKey<Row> =
  | StringKeyOf<Row>
  | {
      primary: {
        key: StringKeyOf<Row>;
        format?: SelectFormatFn<Row[StringKeyOf<Row>], Row>;
      };
      columns?: Array<{
        key: StringKeyOf<Row>;
        width?: number;
        format?: SelectFormatFn<Row[StringKeyOf<Row>], Row>;
      }>;
    };

export interface FieldRendererProps<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
  TRow extends Record<string, unknown> = Record<string, unknown>
> {
  control: Control<TFieldValues>;
  name: TName;
  fieldType: FormFieldType;
  label?: string;
  description?: string;
  show?: (values: TFieldValues) => boolean;
  placeholder?: string;
  disabled?: boolean;
  required?: boolean;
  hideLabel?: boolean;
  hideDescription?: boolean;
  hideMessage?: boolean;
  height?: InputHeight;
  colSpan?: FieldColSpan;
  prefix?: ReactNode;
  suffix?: ReactNode;
  wrapperClassName?: string;
  className?: string;
  inputClassName?: string;
  labelClassName?: string;
  descriptionClassName?: string;
  messageClassName?: string;
  inputProps?: ComponentProps<"input">;
  textareaProps?: ComponentProps<"textarea">;
  passwordProps?: ComponentProps<"input">;
  switchProps?: ComponentProps<typeof Switch>;
  data?: TRow[];
  labelKey?: StringKeyOf<TRow>;
  valueKey?: StringKeyOf<TRow>;
  selectLabelKey?: SelectLabelKey<TRow>;
  radioOrientation?: "horizontal" | "vertical";
  sliderMin?: number;
  sliderMax?: number;
  sliderStep?: number;
  showSliderValue?: boolean;
  otpLength?: number;
  maxSelected?: number;
  numberMin?: number;
  numberMax?: number;
  numberStep?: number;
  loadOptions?: (query: string) => Promise<TRow[]>;
  debounceTime?: number;
  onAddNew?: () => void;
  addNewLabel?: string;
  borderless?: boolean;
  iconSearch?: boolean;
  currencyLocale?: string;
  decimalPlaces?: number;
  thousandSeparator?: boolean;
  trimTrailingZeros?: boolean;
  percentDecimalPlaces?: number;
  textAlign?: "left" | "right";
  mask?: string;
  maskPlaceholder?: string;
  renderSkeleton?: (
    field: ControllerRenderProps<TFieldValues, TName>
  ) => ReactNode;
  loaderMode?: "spinner" | "skeleton";
  loaderSize?: "sm" | "md" | "lg";
  loaderRadius?: "none" | "sm" | "md" | "lg";
  type?: ComponentProps<"input">["type"];
}

export interface FieldControlProps<
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>,
  TRow extends Record<string, unknown> = Record<string, unknown>
> {
  field: ControllerRenderProps<TFieldValues, TName>;
  fieldId: string;
  descriptionId: string;
  messageId: string;
  invalid: boolean;
  props: FieldRendererProps<TFieldValues, TName, TRow>;
}

export interface LazyFieldInputProps {
  field: ControllerRenderProps<FieldValues, string>;
  props: FieldRendererProps<FieldValues, string, Record<string, unknown>>;
  disabled?: boolean;
  className?: string;
}

/** @deprecated Use FieldRendererProps instead. */
export type CustomProps<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
  TRow extends Record<string, unknown> = Record<string, unknown>
> = FieldRendererProps<TFieldValues, TName, TRow>;

/** @deprecated Use FieldControlProps instead. */
export type RenderInputProps<
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>
> = FieldControlProps<TFieldValues, TName>;

export * from "./constants";
export * from "./types";
export * from "./FieldRenderer";
export * from "./FieldSkeleton";
export * from "./render-field-control";

export const applyMask = (value: string, mask: string): string => {
  const digits = value.replace(/\D/g, "");
  let result = "";
  let digitIndex = 0;

  for (let i = 0; i < mask.length; i++) {
    if (digitIndex >= digits.length) break;

    if (mask[i] === "#") {
      result += digits[digitIndex];
      digitIndex++;
    } else {
      result += mask[i];
    }
  }

  return result;
};

export const formatCurrency = (
  value: number,
  locale: string = "en-PH",
  decimals: number = 2,
  useThousands: boolean = true,
  trimZeros: boolean = false
): string => {
  if (isNaN(value)) return "";

  const options: Intl.NumberFormatOptions = {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
    useGrouping: useThousands,
  };

  let formatted = new Intl.NumberFormat(locale, options).format(value);

  // Remove trailing zeros (optional)
  if (trimZeros) {
    formatted = formatted.replace(/\.?0+$/, "");
  }

  return formatted;
};


export const parseCurrency = (value: string): number | null => {
  if (!value) return null;
  const cleaned = value.replace(/[^0-9.-]+/g, "");
  const num = Number(cleaned);
  return isNaN(num) ? null : num;
};

"use client";

import {
  KeyboardEvent,
  useCallback,
  useEffect,
  useRef,
  useState,
} from "react";
import { Loader2, Plus, Search, X } from "lucide-react";

import {
  InputHeight,
  SelectLabelKey,
  StringKeyOf,
} from "@/components/forms/core/types";
import { cn } from "@/lib/utils";

export interface AsyncSelectFieldProps<T extends Record<string, unknown>> {
  value: string | number | null;
  onChange: (value: string | number | null) => void;
  data?: T[];
  loadOptions?: (query: string) => Promise<T[]>;
  valueKey: StringKeyOf<T>;
  selectLabelKey: SelectLabelKey<T>;
  placeholder?: string;
  disabled?: boolean;
  debounceTime?: number;
  borderless?: boolean;
  height?: InputHeight;
  iconSearch?: boolean;
  onAddNew?: () => void;
  addNewLabel?: string;
}

function useDebounce<T>(value: T, delay = 300) {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debounced;
}

function getPrimary<T extends Record<string, unknown>>(
  item: T,
  key: SelectLabelKey<T>
): string {
  if (typeof key === "string") {
    return item[key] != null ? String(item[key]) : "";
  }

  const raw = item[key.primary.key];
  return key.primary.format
    ? String(key.primary.format(raw, item))
    : String(raw ?? "");
}

function getColumns<T extends Record<string, unknown>>(
  item: T,
  key: SelectLabelKey<T>
) {
  if (typeof key === "string" || !key.columns) return [];

  return key.columns.map((column) => {
    const raw = item[column.key];
    const formatted = column.format ? column.format(raw, item) : raw;

    return {
      width: column.width ?? 140,
      value: formatted != null ? String(formatted) : "",
    };
  });
}

const HEIGHT_CLASSES: Record<InputHeight, string> = {
  sm: "h-8",
  md: "h-9",
  lg: "h-10",
  xl: "h-11",
  auto: "h-auto",
};

const PADDING_CLASSES: Record<
  InputHeight,
  { x: string; iconLeft: string; iconRight: string }
> = {
  sm: { x: "px-2", iconLeft: "left-2", iconRight: "right-2" },
  md: { x: "px-3", iconLeft: "left-3", iconRight: "right-3" },
  lg: { x: "px-3", iconLeft: "left-3", iconRight: "right-3" },
  xl: { x: "px-4", iconLeft: "left-4", iconRight: "right-4" },
  auto: { x: "px-3", iconLeft: "left-3", iconRight: "right-3" },
};

export function AsyncSelectField<T extends Record<string, unknown>>({
  value,
  onChange,
  data,
  loadOptions,
  valueKey,
  selectLabelKey,
  placeholder = "Select...",
  disabled = false,
  debounceTime = 300,
  height = "md",
  iconSearch = false,
  onAddNew,
  addNewLabel = "Add New",
}: AsyncSelectFieldProps<T>) {
  const containerRef = useRef<HTMLDivElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const [query, setQuery] = useState("");
  const [options, setOptions] = useState<T[]>([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [highlightIndex, setHighlightIndex] = useState(-1);
  const [position, setPosition] = useState<"above" | "below">("below");

  const debouncedQuery = useDebounce(query, debounceTime);
  const hasStatic = Array.isArray(data) && data.length > 0;
  const padding = PADDING_CLASSES[height];

  const fetchList = useCallback(
    async (search: string): Promise<T[]> => {
      const normalizedQuery = search.toLowerCase();

      if (hasStatic && data) {
        return data.filter((item) =>
          getPrimary(item, selectLabelKey).toLowerCase().includes(normalizedQuery)
        );
      }

      return loadOptions ? loadOptions(search) : [];
    },
    [data, hasStatic, loadOptions, selectLabelKey]
  );

  useEffect(() => {
    if (value == null) return;

    const sourcePromise =
      hasStatic && data
        ? Promise.resolve(data)
        : loadOptions?.("") ?? Promise.resolve([]);

    sourcePromise.then((source) => {
      const found = source.find((item) => item[valueKey] === value);
      if (found) setQuery(getPrimary(found, selectLabelKey));
    });
  }, [data, hasStatic, loadOptions, selectLabelKey, value, valueKey]);

  useEffect(() => {
    let cancelled = false;

    const run = async () => {
      setLoading(true);
      const list =
        debouncedQuery.trim() === ""
          ? await fetchList("")
          : await fetchList(debouncedQuery);

      if (cancelled) return;

      setOptions(list);
      setHighlightIndex(list.length > 0 ? 0 : -1);
      setLoading(false);
    };

    void run();

    return () => {
      cancelled = true;
    };
  }, [debouncedQuery, fetchList]);

  const openList = () => {
    setOpen(true);
    requestAnimationFrame(() => inputRef.current?.focus());

    if (hasStatic && data) {
      setOptions(data);
      setHighlightIndex(data.length ? 0 : -1);
      return;
    }

    if (options.length === 0) {
      setLoading(true);
      fetchList("")
        .then((list) => {
          setOptions(list);
          setHighlightIndex(list.length ? 0 : -1);
        })
        .finally(() => setLoading(false));
    }
  };

  const computePlacement = useCallback(() => {
    if (!containerRef.current || !dropdownRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const dropdownHeight = dropdownRef.current.offsetHeight;
    const spaceBelow = window.innerHeight - rect.bottom;
    const spaceAbove = rect.top;

    setPosition(
      spaceBelow < dropdownHeight && spaceAbove > dropdownHeight
        ? "above"
        : "below"
    );
  }, []);

  useEffect(() => {
    if (!open) return;

    const onResize = () => computePlacement();
    window.addEventListener("resize", onResize);
    window.addEventListener("scroll", onResize, true);
    requestAnimationFrame(computePlacement);

    return () => {
      window.removeEventListener("resize", onResize);
      window.removeEventListener("scroll", onResize, true);
    };
  }, [computePlacement, open]);

  useEffect(() => {
    if (!open) return;

    const handler = (event: MouseEvent) => {
      if (
        containerRef.current &&
        !containerRef.current.contains(event.target as Node)
      ) {
        setOpen(false);
      }
    };

    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [open]);

  const onKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
    if (!open) return;

    if (event.key === "ArrowDown") {
      event.preventDefault();
      setHighlightIndex((index) => Math.min(index + 1, options.length));
    }

    if (event.key === "ArrowUp") {
      event.preventDefault();
      setHighlightIndex((index) => Math.max(index - 1, 0));
    }

    if (event.key === "Enter") {
      event.preventDefault();

      if (highlightIndex === options.length && onAddNew) {
        onAddNew();
        setOpen(false);
        return;
      }

      if (highlightIndex >= 0 && highlightIndex < options.length) {
        const item = options[highlightIndex];
        onChange(item[valueKey] as never);
        setQuery(getPrimary(item, selectLabelKey));
        setOpen(false);
      }
    }

    if (event.key === "Escape") setOpen(false);
  };

  const handleClear = () => {
    setQuery("");
    onChange(null);
    setOpen(false);
    inputRef.current?.focus();
  };

  const wrapperClass = cn(
    "relative flex h-full w-full items-center",
    HEIGHT_CLASSES[height],
    disabled && "cursor-not-allowed opacity-50"
  );

  const getLeftPadding = () => (iconSearch ? "pl-10" : padding.x.split(" ")[0]);
  const getRightPadding = () =>
    query || loading ? "pr-10" : padding.x.split(" ")[1] || "pr-3";

  const inputClass = cn(
    "h-full w-full border-0 bg-transparent text-sm leading-none outline-none",
    "placeholder:text-muted-foreground/60 focus-visible:outline-none focus-visible:ring-0",
    disabled && "cursor-not-allowed",
    getLeftPadding(),
    getRightPadding()
  );

  return (
    <div
      ref={containerRef}
      className={cn("relative h-full w-full", open && "z-20")}
    >
      <div className={wrapperClass}>
        {iconSearch && (
          <div
            className={cn(
              "absolute top-1/2 -translate-y-1/2 text-muted-foreground/70",
              padding.iconLeft
            )}
          >
            <Search className="h-4 w-4" />
          </div>
        )}

        <input
          ref={inputRef}
          type="text"
          disabled={disabled}
          placeholder={placeholder}
          value={query}
          onFocus={openList}
          onChange={(event) => {
            setQuery(event.target.value);
            setOpen(true);
          }}
          onKeyDown={onKeyDown}
          className={inputClass}
        />

        {loading && (
          <div
            className={cn(
              "absolute top-1/2 -translate-y-1/2 text-muted-foreground",
              padding.iconRight
            )}
          >
            <Loader2 className="h-4 w-4 animate-spin" />
          </div>
        )}

        {query && !loading && (
          <button
            type="button"
            onClick={handleClear}
            className={cn(
              "absolute top-1/2 -translate-y-1/2 text-muted-foreground transition-colors hover:text-foreground",
              padding.iconRight
            )}
          >
            <X className="h-4 w-4" />
          </button>
        )}
      </div>

      {open && (
        <div
          ref={dropdownRef}
          className={cn(
            "absolute left-0 right-0 z-30 rounded-md border border-border bg-background shadow-md animate-in fade-in zoom-in-95",
            position === "below" ? "top-full mt-1" : "bottom-full mb-1"
          )}
        >
          <div className="max-h-64 overflow-auto py-1">
            {loading && (
              <div className="px-3 py-2 text-sm text-muted-foreground">
                Loading...
              </div>
            )}

            {!loading && options.length === 0 && (
              <div className="px-3 py-3 text-center text-sm text-muted-foreground/80">
                No results found.
              </div>
            )}

            {!loading &&
              options.map((item, index) => {
                const primary = getPrimary(item, selectLabelKey);
                const columns = getColumns(item, selectLabelKey);

                return (
                  <button
                    key={String(item[valueKey])}
                    type="button"
                    onMouseEnter={() => setHighlightIndex(index)}
                    onClick={() => {
                      onChange(item[valueKey] as never);
                      setQuery(primary);
                      setOpen(false);
                    }}
                    className={cn(
                      "flex w-full items-center justify-between px-3 py-2 text-left transition-colors duration-150 hover:bg-accent hover:text-accent-foreground",
                      highlightIndex === index &&
                        "bg-accent text-accent-foreground"
                    )}
                  >
                    <div className="flex-1 truncate text-sm">{primary}</div>

                    {columns.length > 0 && (
                      <div className="ml-4 flex items-center space-x-4 text-xs text-muted-foreground">
                        {columns.map((column, columnIndex) => (
                          <div
                            key={columnIndex}
                            style={{ width: column.width }}
                            className="truncate"
                          >
                            {column.value}
                          </div>
                        ))}
                      </div>
                    )}
                  </button>
                );
              })}
          </div>

          {onAddNew && (
            <div className="sticky bottom-0 border-t border-border bg-background">
              <button
                type="button"
                onClick={() => {
                  onAddNew();
                  setOpen(false);
                }}
                className={cn(
                  "flex w-full items-center gap-2 px-3 py-2 text-sm text-primary transition-colors hover:bg-accent hover:text-accent-foreground",
                  highlightIndex === options.length &&
                    "bg-accent text-accent-foreground"
                )}
              >
                <Plus className="h-4 w-4" /> {addNewLabel}
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

